#!/usr/bin/env python3
"""
gkq_v2_format.py — GKQ v2 binary format helpers.

Self-contained encoder/decoder for GKQ v2 "knot" files. Reusable by:
  - encode-real-model.py (real HF model → GKQ v2)
  - validate-gkq.py (round-trip check against HF original)
  - inference-server-gkq.py (Python serving loader)
  - future Rust GkqBackend in fat-station (matches binary layout)

Binary layout (little-endian, all multi-byte integers little-endian unless noted):

  magic:               4 bytes  = b"GKQ2"
  header_version:      u8       = 2     (was 1 before per-tensor rank + dense aliases)
  model_name_len:      u16      followed by UTF-8 bytes
  arch_len:            u16      followed by UTF-8 bytes
  metadata_json_len:   u32      followed by UTF-8 JSON bytes (KnotConfig)
  num_spectral:        u32
  num_dense:           u32

  spectral_block (repeated num_spectral times):
    name_len:          u16, then UTF-8 bytes
    d_out:             u32
    d_in:              u32
    rank:              u16        ← v2: per-tensor spectral rank
    u_max:             f32
    sigma_max:         f32
    v_max:             f32
    u_q8:              d_out * rank bytes (delta-encoded uint8, row-major shape [d_out, rank])
    sigma_q8:          rank bytes        (delta-encoded uint8)
    v_q8:              rank * d_in bytes (delta-encoded uint8, row-major shape [rank, d_in])

  dense_block (repeated num_dense times):
    name_len:          u16, then UTF-8 bytes
    flags:             u8         ← v2: bit 0 = is_alias
    [if !is_alias:]
      dtype_code:      u8   (0=F32, 1=F16, 2=Q4_K, 3=Q6_K, 4=Q8)
      rank:            u8
      dims:            rank * u32
      byte_length:     u64  (v3; v2 used u32 — reader auto-dispatches on header_version)
      raw:             byte_length bytes
    [if is_alias:]
      alias_target_name_len: u16, then UTF-8 bytes (canonical name being aliased)

Delta encoding (for the q8 arrays inside spectral blocks):
  encode: delta[0] = arr[0]; delta[i] = (arr[i] - arr[i-1]) mod 256
  decode: out[0]   = delta[0]; out[i]   = (out[i-1] + delta[i]) mod 256

Both treat bytes as uint8 with wraparound. This is the encoding the Rust
`GkqBackend` will mirror.
"""

from __future__ import annotations

import io
import json
import struct
from typing import BinaryIO, Dict, List, Optional, Tuple

import numpy as np

# ─────────────────────────────────────────────────────────────────────────────
# CONSTANTS
# ─────────────────────────────────────────────────────────────────────────────

MAGIC: bytes = b"GKQ2"
HEADER_VERSION: int = 3
# v3 bumps dense-block byte_length from u32 to u64 so individual dense
# tensors >= 4 GiB (e.g. Qwen2.5-72B token_embd.weight = 4.98 GiB f32)
# encode without truncation. Reader still accepts v2 files via the
# byte_length_format dispatch in read_dense_tensor.
SUPPORTED_READ_VERSIONS: tuple = (2, 3)

DTYPE_F32: int = 0
DTYPE_F16: int = 1
DTYPE_Q4_K: int = 2
DTYPE_Q6_K: int = 3
DTYPE_Q8: int = 4

DTYPE_NAME = {
    DTYPE_F32: "F32",
    DTYPE_F16: "F16",
    DTYPE_Q4_K: "Q4_K",
    DTYPE_Q6_K: "Q6_K",
    DTYPE_Q8: "Q8",
}

# Default spectral rank for new files. Per-tensor rank lives in each block.
RANK_DEFAULT: int = 64

# Legacy alias: code that still references SPECTRAL_RANK gets the new default.
# (No on-disk files used the old hardcoded value in production.)
SPECTRAL_RANK: int = RANK_DEFAULT

# Dense block flags.
DENSE_FLAG_ALIAS: int = 1 << 0


# ─────────────────────────────────────────────────────────────────────────────
# DELTA CODEC
# ─────────────────────────────────────────────────────────────────────────────


def delta_encode(arr: np.ndarray) -> bytes:
    """Delta-encode a uint8 array with wrapping subtraction.

    delta[0] = arr[0]
    delta[i] = (arr[i] - arr[i-1]) mod 256
    """
    arr = np.ascontiguousarray(arr, dtype=np.uint8).ravel()
    if arr.size == 0:
        return b""
    out = np.empty_like(arr)
    out[0] = arr[0]
    if arr.size > 1:
        # Wrapping subtraction in uint8 happens naturally on uint8 arrays.
        diff = arr[1:].astype(np.int16) - arr[:-1].astype(np.int16)
        out[1:] = (diff & 0xFF).astype(np.uint8)
    return out.tobytes()


def delta_decode(buf: bytes) -> np.ndarray:
    """Inverse of delta_encode. Returns a uint8 array of the same length."""
    arr = np.frombuffer(buf, dtype=np.uint8)
    if arr.size == 0:
        return arr.copy()
    out = np.empty_like(arr)
    out[0] = arr[0]
    if arr.size > 1:
        # Cumulative sum mod 256.
        cum = np.cumsum(arr[1:].astype(np.uint32)) + arr[0]
        out[1:] = (cum & 0xFF).astype(np.uint8)
    return out


# ─────────────────────────────────────────────────────────────────────────────
# HEADER WRITER / READER
# ─────────────────────────────────────────────────────────────────────────────


def write_header(
    f: BinaryIO,
    model_name: str,
    arch: str,
    knot_config_dict: dict,
    num_spectral: int,
    num_dense: int,
) -> None:
    """Write magic + header to an open binary file/stream."""
    f.write(MAGIC)
    f.write(struct.pack("<B", HEADER_VERSION))

    name_bytes = model_name.encode("utf-8")
    f.write(struct.pack("<H", len(name_bytes)))
    f.write(name_bytes)

    arch_bytes = arch.encode("utf-8")
    f.write(struct.pack("<H", len(arch_bytes)))
    f.write(arch_bytes)

    meta_bytes = json.dumps(knot_config_dict, sort_keys=True).encode("utf-8")
    f.write(struct.pack("<I", len(meta_bytes)))
    f.write(meta_bytes)

    f.write(struct.pack("<I", num_spectral))
    f.write(struct.pack("<I", num_dense))


def read_header(f: BinaryIO) -> dict:
    """Read magic + header. Returns dict with keys:
    model_name, arch, knot_config, num_spectral, num_dense, header_version.
    """
    magic = f.read(4)
    if magic != MAGIC:
        raise ValueError(f"Bad magic: expected {MAGIC!r}, got {magic!r}")

    (header_version,) = struct.unpack("<B", f.read(1))
    if header_version not in SUPPORTED_READ_VERSIONS:
        # v1 files are random-bytes placeholders, never shipped. v2/v3 supported.
        raise ValueError(
            f"Unsupported header_version={header_version}; this build reads v{SUPPORTED_READ_VERSIONS}"
        )
    (name_len,) = struct.unpack("<H", f.read(2))
    model_name = f.read(name_len).decode("utf-8")
    (arch_len,) = struct.unpack("<H", f.read(2))
    arch = f.read(arch_len).decode("utf-8")
    (meta_len,) = struct.unpack("<I", f.read(4))
    knot_config = json.loads(f.read(meta_len).decode("utf-8"))
    (num_spectral,) = struct.unpack("<I", f.read(4))
    (num_dense,) = struct.unpack("<I", f.read(4))

    return {
        "header_version": header_version,
        "model_name": model_name,
        "arch": arch,
        "knot_config": knot_config,
        "num_spectral": num_spectral,
        "num_dense": num_dense,
    }


def read_header_only(f: BinaryIO) -> dict:
    """Convenience: read just the header and return as dict (no body parsing)."""
    return read_header(f)


# ─────────────────────────────────────────────────────────────────────────────
# SPECTRAL BLOCK
# ─────────────────────────────────────────────────────────────────────────────


def write_spectral_tensor(
    f: BinaryIO,
    name: str,
    u_q8: np.ndarray,
    sigma_q8: np.ndarray,
    v_q8: np.ndarray,
    u_max: float,
    sigma_max: float,
    v_max: float,
    d_out: int,
    d_in: int,
    rank: int = RANK_DEFAULT,
) -> None:
    """Write one spectral tensor block.

    u_q8 shape: [d_out, rank] uint8 (row-major)
    sigma_q8 shape: [rank] uint8
    v_q8 shape: [rank, d_in] uint8 (row-major)
    Arrays are delta-encoded on write.
    """
    if rank <= 0 or rank > 0xFFFF:
        raise ValueError(f"rank out of range: {rank}")

    u_flat = np.ascontiguousarray(u_q8, dtype=np.uint8).reshape(d_out, rank).ravel()
    v_flat = np.ascontiguousarray(v_q8, dtype=np.uint8).reshape(rank, d_in).ravel()
    s_flat = np.ascontiguousarray(sigma_q8, dtype=np.uint8).reshape(rank)

    assert u_flat.size == d_out * rank, "u_q8 size mismatch"
    assert v_flat.size == rank * d_in, "v_q8 size mismatch"
    assert s_flat.size == rank, "sigma_q8 size mismatch"

    name_bytes = name.encode("utf-8")
    f.write(struct.pack("<H", len(name_bytes)))
    f.write(name_bytes)
    f.write(struct.pack("<II", d_out, d_in))
    f.write(struct.pack("<H", int(rank)))
    f.write(struct.pack("<fff", float(u_max), float(sigma_max), float(v_max)))
    f.write(delta_encode(u_flat))
    f.write(delta_encode(s_flat))
    f.write(delta_encode(v_flat))


def read_spectral_tensor(f: BinaryIO) -> dict:
    """Read one spectral tensor block. Returns dict with:
    name, d_out, d_in, rank, u_max, sigma_max, v_max,
    u_q8 [d_out, rank] uint8, sigma_q8 [rank] uint8, v_q8 [rank, d_in] uint8.
    """
    (name_len,) = struct.unpack("<H", f.read(2))
    name = f.read(name_len).decode("utf-8")
    d_out, d_in = struct.unpack("<II", f.read(8))
    (rank,) = struct.unpack("<H", f.read(2))
    u_max, sigma_max, v_max = struct.unpack("<fff", f.read(12))

    u_buf = f.read(d_out * rank)
    s_buf = f.read(rank)
    v_buf = f.read(rank * d_in)

    u_q8 = delta_decode(u_buf).reshape(d_out, rank)
    sigma_q8 = delta_decode(s_buf)
    v_q8 = delta_decode(v_buf).reshape(rank, d_in)

    return {
        "name": name,
        "d_out": d_out,
        "d_in": d_in,
        "rank": int(rank),
        "u_max": u_max,
        "sigma_max": sigma_max,
        "v_max": v_max,
        "u_q8": u_q8,
        "sigma_q8": sigma_q8,
        "v_q8": v_q8,
    }


def reconstruct_spectral(block: dict) -> np.ndarray:
    """Reconstruct W = U @ diag(sigma) @ V from a spectral block dict.

    Mirrors the signed/unsigned quantization done by the encoder
    (encode-real-model.py:_spectral_quantize):
      U and Vt are offset-128 signed-uint8: x = ((q - 128) / 127) * max
      sigma is unsigned: x = (q / 255) * max
    """
    U = ((block["u_q8"].astype(np.float32) - 128.0) / 127.0) * float(block["u_max"])
    sigma = (block["sigma_q8"].astype(np.float32) / 255.0) * float(block["sigma_max"])
    Vt = ((block["v_q8"].astype(np.float32) - 128.0) / 127.0) * float(block["v_max"])
    # U is [d_out, rank], Vt is [rank, d_in]; result is [d_out, d_in].
    return (U * sigma[np.newaxis, :]) @ Vt


# ─────────────────────────────────────────────────────────────────────────────
# DENSE BLOCK
# ─────────────────────────────────────────────────────────────────────────────


def _numpy_dtype_to_code(dtype: np.dtype) -> int:
    if dtype == np.float32:
        return DTYPE_F32
    if dtype == np.float16:
        return DTYPE_F16
    # bfloat16 is not natively supported by numpy; callers must convert first.
    raise ValueError(f"Unsupported dense dtype: {dtype}")


def _code_to_numpy_dtype(code: int):
    if code == DTYPE_F32:
        return np.float32
    if code == DTYPE_F16:
        return np.float16
    # For Q4_K, Q6_K, Q8 we keep raw bytes (no numpy view) — return None.
    return None


def write_dense_tensor(
    f: BinaryIO,
    name: str,
    arr: np.ndarray,
    dtype_code: int = None,
    raw_bytes: bytes = None,
) -> None:
    """Write one dense tensor block (non-aliased).

    Two modes:
      - arr is a numpy ndarray (F32 or F16) → infer dtype_code from arr.dtype.
      - raw_bytes is provided (for pre-quantized payloads) along with explicit
        dtype_code and arr (which is then used only for shape via arr.shape).
    """
    name_bytes = name.encode("utf-8")
    if raw_bytes is None:
        arr = np.ascontiguousarray(arr)
        if dtype_code is None:
            dtype_code = _numpy_dtype_to_code(arr.dtype)
        raw_bytes = arr.tobytes()

    dims = tuple(int(d) for d in arr.shape)
    rank = len(dims)
    if rank > 255:
        raise ValueError(f"rank > 255 not supported: {name}")

    f.write(struct.pack("<H", len(name_bytes)))
    f.write(name_bytes)
    f.write(struct.pack("<B", 0))  # flags: not an alias
    f.write(struct.pack("<B", int(dtype_code)))
    f.write(struct.pack("<B", rank))
    for d in dims:
        f.write(struct.pack("<I", int(d)))
    # v3: u64 byte_length (was u32 in v2; capped at 4 GiB per tensor)
    f.write(struct.pack("<Q", len(raw_bytes)))
    f.write(raw_bytes)


def write_dense_alias(f: BinaryIO, name: str, alias_target: str) -> None:
    """Write a dense alias block: `name` is a pointer to another dense tensor
    stored under `alias_target`. Used for tied embeddings (output.weight →
    token_embd.weight) so we don't duplicate hundreds of MB on disk.
    """
    name_bytes = name.encode("utf-8")
    target_bytes = alias_target.encode("utf-8")
    f.write(struct.pack("<H", len(name_bytes)))
    f.write(name_bytes)
    f.write(struct.pack("<B", DENSE_FLAG_ALIAS))
    f.write(struct.pack("<H", len(target_bytes)))
    f.write(target_bytes)


def read_dense_tensor(f: BinaryIO, header_version: int = HEADER_VERSION) -> dict:
    """Read one dense tensor block (alias or full). Returns dict with:
    name, is_alias, alias_target (when is_alias), dtype_code, dtype_name,
    dims, raw (bytes), array (numpy view if F32/F16 else None).

    Alias blocks have is_alias=True and only the `alias_target` field set;
    the caller is responsible for resolving the alias against an earlier-read
    dense tensor.

    `header_version` is needed because v2 packs byte_length as u32 and v3 as
    u64 — the encoded length matters for stream position correctness.
    """
    (name_len,) = struct.unpack("<H", f.read(2))
    name = f.read(name_len).decode("utf-8")
    (flags,) = struct.unpack("<B", f.read(1))
    is_alias = bool(flags & DENSE_FLAG_ALIAS)

    if is_alias:
        (target_len,) = struct.unpack("<H", f.read(2))
        target = f.read(target_len).decode("utf-8")
        return {
            "name": name,
            "is_alias": True,
            "alias_target": target,
            "dtype_code": None,
            "dtype_name": "ALIAS",
            "dims": (),
            "raw": b"",
            "array": None,
        }

    (dtype_code,) = struct.unpack("<B", f.read(1))
    (rank,) = struct.unpack("<B", f.read(1))
    dims = struct.unpack(f"<{rank}I", f.read(4 * rank))
    # v2: u32 byte_length; v3: u64 byte_length
    if header_version <= 2:
        (byte_len,) = struct.unpack("<I", f.read(4))
    else:
        (byte_len,) = struct.unpack("<Q", f.read(8))
    raw = f.read(byte_len)

    np_dtype = _code_to_numpy_dtype(dtype_code)
    array = None
    if np_dtype is not None:
        array = np.frombuffer(raw, dtype=np_dtype).reshape(dims)

    return {
        "name": name,
        "is_alias": False,
        "alias_target": None,
        "dtype_code": dtype_code,
        "dtype_name": DTYPE_NAME.get(dtype_code, f"UNKNOWN({dtype_code})"),
        "dims": dims,
        "raw": raw,
        "array": array,
    }


# ─────────────────────────────────────────────────────────────────────────────
# WHOLE-FILE CONVENIENCE READER
# ─────────────────────────────────────────────────────────────────────────────


def read_all(f: BinaryIO, resolve_aliases: bool = True) -> dict:
    """Read an entire GKQ v2 file from an open binary stream. Returns:
      header, spectral (list of dicts), dense (list of dicts).

    If resolve_aliases=True (default), alias dense blocks get their `array`,
    `raw`, `dims`, and `dtype_code` populated by looking up the target in
    earlier dense blocks (writers always emit the target before the alias).
    """
    header = read_header(f)
    hv = header["header_version"]
    spectral = [read_spectral_tensor(f) for _ in range(header["num_spectral"])]
    dense = [read_dense_tensor(f, header_version=hv) for _ in range(header["num_dense"])]

    if resolve_aliases:
        by_name: Dict[str, dict] = {}
        for blk in dense:
            if not blk["is_alias"]:
                by_name[blk["name"]] = blk
        for blk in dense:
            if blk["is_alias"]:
                tgt = by_name.get(blk["alias_target"])
                if tgt is None:
                    raise ValueError(
                        f"dense alias {blk['name']!r} points to unknown target "
                        f"{blk['alias_target']!r}"
                    )
                blk["array"] = tgt["array"]
                blk["raw"] = tgt["raw"]
                blk["dims"] = tgt["dims"]
                blk["dtype_code"] = tgt["dtype_code"]
                blk["dtype_name"] = tgt["dtype_name"]
    return {"header": header, "spectral": spectral, "dense": dense}


def read_file(path: str) -> dict:
    with open(path, "rb") as f:
        return read_all(f)


# ─────────────────────────────────────────────────────────────────────────────
# SMOKE TEST (run `python3 gkq_v2_format.py`)
# ─────────────────────────────────────────────────────────────────────────────


def _smoke_test() -> None:
    # Delta codec round-trip.
    rng = np.random.default_rng(0)
    arr = rng.integers(0, 256, size=1024, dtype=np.uint8)
    enc = delta_encode(arr)
    dec = delta_decode(enc)
    assert np.array_equal(arr, dec), "delta codec round-trip failed"

    # Specific small array from the prompt.
    a = np.array([10, 20, 15, 50, 5], dtype=np.uint8)
    assert np.array_equal(delta_decode(delta_encode(a)), a), "5-element round-trip failed"

    # Full-file round-trip with one spectral + one dense block + one alias.
    buf = io.BytesIO()
    write_header(
        buf,
        model_name="smoke",
        arch="qwen2",
        knot_config_dict={"hidden_dim": 8, "num_layers": 1},
        num_spectral=1,
        num_dense=2,
    )

    rank = 4  # exercise non-default rank
    d_out, d_in = 6, 8
    u_q8 = rng.integers(0, 256, size=(d_out, rank), dtype=np.uint8)
    sigma_q8 = rng.integers(0, 256, size=(rank,), dtype=np.uint8)
    v_q8 = rng.integers(0, 256, size=(rank, d_in), dtype=np.uint8)
    write_spectral_tensor(buf, "blk.0.attn_q.weight", u_q8, sigma_q8, v_q8, 1.5, 0.7, 1.2, d_out, d_in, rank=rank)

    dense_arr = rng.standard_normal((4, 4)).astype(np.float32)
    write_dense_tensor(buf, "token_embd.weight", dense_arr)
    write_dense_alias(buf, "output.weight", "token_embd.weight")

    buf.seek(0)
    out = read_all(buf)
    assert out["header"]["num_spectral"] == 1
    assert out["header"]["num_dense"] == 2
    assert out["header"]["header_version"] == HEADER_VERSION
    sb = out["spectral"][0]
    assert sb["name"] == "blk.0.attn_q.weight"
    assert sb["rank"] == rank
    assert np.array_equal(sb["u_q8"], u_q8)
    assert np.array_equal(sb["sigma_q8"], sigma_q8)
    assert np.array_equal(sb["v_q8"], v_q8)
    assert out["dense"][0]["name"] == "token_embd.weight"
    assert np.array_equal(out["dense"][0]["array"], dense_arr)
    # Alias was resolved.
    alias = out["dense"][1]
    assert alias["name"] == "output.weight"
    assert alias["is_alias"] is True
    assert alias["alias_target"] == "token_embd.weight"
    assert np.array_equal(alias["array"], dense_arr)
    print("gkq_v2_format: smoke test PASSED")


if __name__ == "__main__":
    _smoke_test()
